export const ButtonGroupPopover = (): Html =>
  ButtonGroup<never>({
    children: [
      button([icon('bot'), 'Copilot'], { variant: 'outline' }),
      popoverTriggerButton([icon('chevronDown')], {
        variant: 'outline',
        size: 'icon',
        ariaLabel: 'Open Popover',
      }),
    ],
  })

const rtlLabels = {
  archive: 'أرشفة',
  report: 'تقرير',
  snooze: 'تأجيل',
}

export const ButtonGroupRtl = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Dir('rtl')],
    [
      ButtonGroup<never>({
        dir: 'rtl',
        children: [
          ButtonGroup<never>({
            dir: 'rtl',
            className: 'hidden sm:flex',
            children: [
              button([icon('arrowLeft', [h.Class('rtl:rotate-180')])], {
                variant: 'outline',
                size: 'icon',
                ariaLabel: 'Go Back',
              }),
            ],
          }),
          ButtonGroup<never>({
            dir: 'rtl',
            children: [
              button([rtlLabels.archive], { variant: 'outline' }),
              button([rtlLabels.report], { variant: 'outline' }),
            ],
          }),
          ButtonGroup<never>({
            dir: 'rtl',
            children: [
              button([rtlLabels.snooze], { variant: 'outline' }),
              dropdownTriggerButton(
                'button-group-rtl-more-options',
                [icon('moreHorizontal')],
                {
                  variant: 'outline',
                  size: 'icon',
                  ariaLabel: 'More Options',
                },
              ),
            ],
          }),
        ],
      }),
    ],
  )
}

export const ButtonGroupSelect = (): Html => {
  const h = html<never>()

  return ButtonGroup<never>({
    children: [
      ButtonGroup<never>({
        children: [
          currencySelect(),
          input('10.00', [h.Attribute('pattern', '[0-9]*')]),
        ],
      }),
      ButtonGroup<never>({
        children: [
          button([icon('arrowRight')], {
            variant: 'outline',
            size: 'icon',
            ariaLabel: 'Send',
          }),
        ],
      }),
    ],
  })
}

